import React from 'react';
import {
  Container,
  Box,
  Typography,
  Grid,
  Card,
  CardContent,
  CardMedia,
  CardActions,
  Button,
  Chip,
  Tabs,
  Tab,
  CircularProgress
} from '@mui/material';
import {
  Edit as EditIcon,
  Delete as DeleteIcon,
  Visibility as ViewIcon
} from '@mui/icons-material';
import { useListings } from '../context/ListingContext';

const Listings = () => {
  const { listings, loading } = useListings();
  const [activeTab, setActiveTab] = React.useState(0);

  // In a real app, you would filter by user's listings
  // For now, we'll just use all listings
  const user = { id: 1 }; // Mock user
  const userActiveListings = listings.filter(listing => listing.owner === 'You');
  const userInactiveListings = listings.filter(listing => listing.owner !== 'You');

  const renderListingCard = (listing) => (
    <Card sx={{ borderRadius: '16px', boxShadow: '0 4px 12px rgba(0, 128, 128, 0.1)', mb: 3 }}>
      <CardMedia
        component="img"
        height="200"
        image={listing.image}
        alt={listing.title}
        sx={{ objectFit: 'cover' }}
      />
      <CardContent>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', mb: 1 }}>
          <Typography variant="h6" sx={{ fontWeight: 600 }}>
            {listing.title}
          </Typography>
          <Chip 
            label={`${listing.rating} ★`} 
            size="small" 
            sx={{ 
              backgroundColor: '#E0F7F7', 
              color: '#008080', 
              fontWeight: 600,
              height: '24px'
            }} 
          />
        </Box>
        <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
          {listing.description}
        </Typography>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <Typography variant="subtitle1" sx={{ fontWeight: 700, color: '#008080' }}>
            €{listing.price_per_day}/day
          </Typography>
          <Typography variant="body2" color="text.secondary">
            Category: {listing.category}
          </Typography>
        </Box>
      </CardContent>
      <CardActions sx={{ justifyContent: 'flex-end', pb: 2, pr: 2 }}>
        <Button 
          size="small"
          sx={{ 
            color: '#008080',
            fontWeight: 600,
            '&:hover': {
              backgroundColor: 'rgba(0, 128, 128, 0.1)',
            }
          }}
          startIcon={<ViewIcon />}
        >
          View
        </Button>
        <Button 
          size="small"
          sx={{ 
            color: '#008080',
            fontWeight: 600,
            '&:hover': {
              backgroundColor: 'rgba(0, 128, 128, 0.1)',
            }
          }}
          startIcon={<EditIcon />}
        >
          Edit
        </Button>
        <Button 
          size="small"
          sx={{ 
            color: '#C62828',
            fontWeight: 600,
            '&:hover': {
              backgroundColor: 'rgba(198, 40, 40, 0.1)',
            }
          }}
          startIcon={<DeleteIcon />}
        >
          Delete
        </Button>
      </CardActions>
    </Card>
  );

  if (loading) {
    return (
      <Container maxWidth="lg">
        <Box sx={{ 
          display: 'flex', 
          justifyContent: 'center', 
          alignItems: 'center', 
          height: '60vh' 
        }}>
          <CircularProgress sx={{ color: '#008080' }} />
        </Box>
      </Container>
    );
  }

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Typography 
          variant="h4" 
          sx={{ 
            fontWeight: 700, 
            color: '#008080',
            mb: 3,
            textAlign: 'center'
          }}
        >
          My Listings
        </Typography>
        
        <Box sx={{ 
          backgroundColor: 'white', 
          borderRadius: '16px', 
          boxShadow: '0 4px 12px rgba(0, 128, 128, 0.1)',
          mb: 4
        }}>
          <Tabs 
            value={activeTab} 
            onChange={(e, newValue) => setActiveTab(newValue)}
            sx={{ 
              '& .MuiTabs-indicator': {
                backgroundColor: '#008080',
              }
            }}
          >
            <Tab 
              label={`Active (${userActiveListings.length})`} 
              sx={{ 
                fontWeight: 600,
                '&.Mui-selected': {
                  color: '#008080',
                }
              }} 
            />
            <Tab 
              label={`Inactive (${userInactiveListings.length})`} 
              sx={{ 
                fontWeight: 600,
                '&.Mui-selected': {
                  color: '#008080',
                }
              }} 
            />
          </Tabs>
          
          <Box sx={{ p: 3 }}>
            {activeTab === 0 && (
              <Box>
                <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
                  Active Listings
                </Typography>
                {userActiveListings.length > 0 ? (
                  userActiveListings.map(listing => renderListingCard(listing))
                ) : (
                  <Typography variant="body1" sx={{ textAlign: 'center', py: 4, color: '#5A7D8C' }}>
                    You don't have any active listings. <Button sx={{ ml: 1, textTransform: 'none' }} href="/add">Add a new listing</Button>
                  </Typography>
                )}
              </Box>
            )}
            
            {activeTab === 1 && (
              <Box>
                <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
                  Inactive Listings
                </Typography>
                {userInactiveListings.length > 0 ? (
                  userInactiveListings.map(listing => renderListingCard(listing))
                ) : (
                  <Typography variant="body1" sx={{ textAlign: 'center', py: 4, color: '#5A7D8C' }}>
                    You don't have any inactive listings.
                  </Typography>
                )}
              </Box>
            )}
          </Box>
        </Box>
      </Box>
    </Container>
  );
};

export default Listings;
